impl Solution { pub fn stone_game_vii(stones: Vec<i32>) -> i32 { let black_n = stones.len(); let mut black_pre = vec![0; black_n + 1]; for i in 0..black_n { black_pre[i+1] = black_pre[i] + stones[i]; } let mut black_dp = vec![0; black_n]; for i in (0..black_n-1).rev() { for j in i+1..black_n { black_dp[j] = (black_pre[j+1] - black_pre[i+1] - black_dp[j]).max(black_pre[j] - black_pre[i] - black_dp[j-1]); } } black_dp[black_n-1] } }